/**
 * Project (lat, lng) onto a state's viewBox using equirectangular projection
 * with latitude-corrected lng scaling. Accurate enough at state scale.
 * Returns [x, y] in viewBox units, or null if the geom isn't known.
 */
function locals_project_latlng($lat, $lng, $slug) {
    $geom = locals_state_map_geom($slug);
    if (!$geom) { return null; }
    [$min_lng, $min_lat, $max_lng, $max_lat] = $geom['bbox'];
    $mid_lat   = ($min_lat + $max_lat) / 2.0;
    $lng_scale = cos(deg2rad($mid_lat));
    $width_d   = ($max_lng - $min_lng) * $lng_scale;
    $height_d  = $max_lat - $min_lat;
    $x = ($lng - $min_lng) * $lng_scale / $width_d * $geom['view_w'];
    $y = ($max_lat - $lat) / $height_d * $geom['view_h'];
    return [round($x, 2), round($y, 2)];
}

