/**
 * Resolve a town's [lat, lng] from ACF fields, then known-town fallback.
 */
function locals_town_latlng($town_post) {
    if (function_exists('get_field')) {
        $lat = get_field('latitude',  $town_post->ID);
        $lng = get_field('longitude', $town_post->ID);
        if ($lat !== '' && $lat !== null && $lng !== '' && $lng !== null) {
            return [(float) $lat, (float) $lng];
        }
    }
    return locals_known_town_latlng($town_post->post_name);
}
